export const getListForecastUrl = (params?: ListForecastParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : String(value))
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/forecast?${stringifiedParams}` : `/api/forecast`
}

/**
 * @summary List forecasted transactions (optionally filtered by date range)
 */
